const config = {
  "previewFeatures": [],
  "clientVersion": "7.8.0",
  "engineVersion": "3c6e192761c0362d496ed980de936e2f3cebcd3a",
  "activeProvider": "postgresql",
  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Get a free hosted Postgres database in seconds: `npx create-db`\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"./generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// =============================================================\n// ENUMS\n// =============================================================\n\nenum TipoSanguineo {\n  A_POS  @map(\"A+\")\n  A_NEG  @map(\"A-\")\n  B_POS  @map(\"B+\")\n  B_NEG  @map(\"B-\")\n  O_POS  @map(\"O+\")\n  O_NEG  @map(\"O-\")\n  AB_POS @map(\"AB+\")\n  AB_NEG @map(\"AB-\")\n}\n\nenum StatusDoador {\n  ativo\n  inativo\n  bloqueado\n}\n\nenum StatusHospital {\n  ativo\n  suspenso\n  inativo\n}\n\nenum NivelUrgencia {\n  urgente\n  emergencia\n}\n\nenum StatusPedido {\n  ativo\n  fechado\n  cancelado\n}\n\nenum StatusNotificacao {\n  sucesso\n  falha\n}\n\nenum StatusAgenda {\n  pendente // aguardando avaliação do hospital\n  confirmada // hospital confirmou\n  rejeitada // hospital rejeitou\n  concluida // doação realizada\n  cancelada // doador cancelou\n}\n\nenum StatusPedidoDoacao {\n  pendente\n  aceite\n  rejeitado\n  cancelado\n}\n\nenum StatusMensagem {\n  enviada\n  lida\n}\n\nenum StatusPedidoEntreHospitais {\n  pendente\n  aceite\n  rejeitado\n  cancelado\n}\n\n// =============================================================\n// GEOGRAFIA — 1FN\n// provincia e municipio eram strings repetidas em Doador e Hospital.\n// Passam a ser entidades com PK própria, ligadas por FK.\n// =============================================================\n\nmodel Provincia {\n  id_provincia Int    @id @default(autoincrement())\n  nome         String @unique @db.VarChar(50)\n\n  municipios Municipio[]\n\n  @@map(\"provincia\")\n}\n\n// Municipio depende apenas de id_municipio (2FN ok).\n// nome pode repetir entre províncias → chave única composta.\nmodel Municipio {\n  id_municipio Int    @id @default(autoincrement())\n  id_provincia Int\n  nome         String @db.VarChar(60)\n\n  provincia Provincia  @relation(fields: [id_provincia], references: [id_provincia])\n  doadores  Doador[]\n  hospitais Hospital[]\n  pedidos   Pedido[]\n\n  @@unique([id_provincia, nome])\n  @@index([id_provincia])\n  @@map(\"municipio\")\n}\n\n// =============================================================\n// REGRA DE CLASSIFICAÇÃO — 3FN\n// Antes: nivel (bronze/prata/ouro/elite) estava em EstatisticaDoador,\n// criando dependência transitiva: nivel → pontuacao → id_doador.\n// Agora: as faixas ficam aqui; o nível é calculado na aplicação.\n// =============================================================\n\nmodel RegraClassificacao {\n  id_regra         Int    @id @default(autoincrement())\n  nome_nivel       String @unique @db.VarChar(20)\n  pontuacao_minima Int\n  pontuacao_maxima Int? // NULL = sem teto (elite)\n\n  @@map(\"regra_classificacao\")\n}\n\n// =============================================================\n// 1. DOADOR\n// 3FN: data_ultima_doacao removida — é MAX(data_doacao) de\n// HistoricoDoacao; mantê-la aqui causaria anomalia de atualização.\n// 1FN: provincia/municipio substituídos por FK id_municipio.\n// =============================================================\n\nmodel Doador {\n  id_doador         Int           @id @default(autoincrement())\n  nome_completo     String        @db.VarChar(100)\n  telefone          String        @unique @db.VarChar(15)\n  email             String?       @unique @db.VarChar(80)\n  senha_hash        String        @db.VarChar(255)\n  tipo_sanguineo    TipoSanguineo\n  id_municipio      Int\n  data_nascimento   DateTime?     @db.Date\n  data_cadastro     DateTime      @default(now())\n  status            StatusDoador  @default(ativo)\n  consentimento_sms Boolean       @default(true)\n\n  municipio        Municipio          @relation(fields: [id_municipio], references: [id_municipio])\n  estatisticas     EstatisticaDoador?\n  historicoDoacoes HistoricoDoacao[]\n  notificacoes     Notificacao[]\n  agendamentos     Agenda[]\n  pedidosDoacoes   PedidoDoacao[]\n  sessoes          SessaoDoador[]\n  logs             LogAcesso[]\n\n  @@index([tipo_sanguineo])\n  @@index([id_municipio])\n  @@map(\"doador\")\n}\n\n// =============================================================\n// 2. HISTÓRICO DE DOAÇÕES\n// Entidade própria: cada doação é um facto independente.\n// Elimina data_ultima_doacao de Doador (anomalia de atualização).\n// Permite calcular total_doacoes e total_centros via agregação.\n// =============================================================\n\nmodel HistoricoDoacao {\n  id_historico Int      @id @default(autoincrement())\n  id_doador    Int\n  id_hospital  Int\n  data_doacao  DateTime @db.Date\n  observacao   String?  @db.VarChar(255)\n\n  doador   Doador   @relation(fields: [id_doador], references: [id_doador])\n  hospital Hospital @relation(fields: [id_hospital], references: [id_hospital])\n\n  @@index([id_doador])\n  @@index([id_hospital])\n  @@index([data_doacao])\n  @@map(\"historico_doacao\")\n}\n\n// =============================================================\n// 3. ESTATÍSTICA E GAMIFICAÇÃO DO DOADOR\n// 3FN: nivel removido (dependia de pontuacao, não de id_doador).\n// Campos de cache documentados como intencionais para performance.\n// =============================================================\n\nmodel EstatisticaDoador {\n  id_estatistica     Int      @id @default(autoincrement())\n  id_doador          Int      @unique\n  /// Cache: COUNT(*) em HistoricoDoacao WHERE id_doador = X\n  total_doacoes      Int      @default(0)\n  /// Cache: total_doacoes * 3 (estimativa médica padrão)\n  vidas_salvas       Int      @default(0)\n  /// Cache: COUNT(DISTINCT id_hospital) em HistoricoDoacao WHERE id_doador = X\n  total_centros      Int      @default(0)\n  /// Pontos acumulados por frequência; nível determinado via RegraClassificacao\n  pontuacao          Int      @default(0)\n  ultima_atualizacao DateTime @default(now()) @updatedAt\n\n  doador Doador @relation(fields: [id_doador], references: [id_doador], onDelete: Cascade)\n\n  @@map(\"estatistica_doador\")\n}\n\n// =============================================================\n// 4. HOSPITAL\n// 1FN: provincia/municipio substituídos por FK id_municipio.\n// 2FN/3FN: todos os atributos dependem exclusivamente de id_hospital.\n// =============================================================\n\nmodel Hospital {\n  id_hospital   Int            @id @default(autoincrement())\n  nome          String         @db.VarChar(100)\n  nif           String         @unique @db.VarChar(20)\n  id_municipio  Int\n  endereco      String         @db.VarChar(150)\n  telefone      String         @db.VarChar(15)\n  email         String         @unique @db.VarChar(80)\n  senha_hash    String         @db.VarChar(255)\n  data_cadastro DateTime       @default(now())\n  status        StatusHospital @default(ativo)\n\n  municipio             Municipio              @relation(fields: [id_municipio], references: [id_municipio])\n  pedidos               Pedido[]\n  stocks                Stock[]\n  agendamentos          Agenda[]\n  pedidosDoacoes        PedidoDoacao[]\n  historicosDoacoes     HistoricoDoacao[]\n  sessoes               SessaoAdmin[]\n  logs                  LogAcesso[]\n  mensagensEnviadas     Mensagem[]             @relation(\"Remetente\")\n  mensagensRecebidas    Mensagem[]             @relation(\"Destinatario\")\n  pedidosEntreEnviados  PedidoEntreHospitais[] @relation(\"HospitalSolicitante\")\n  pedidosEntreRecebidos PedidoEntreHospitais[] @relation(\"HospitalFornecedor\")\n\n  @@index([id_municipio])\n  @@map(\"hospital\")\n}\n\n// =============================================================\n// 5. STOCK DE SANGUE\n// @@unique garante 2FN: quantidade_bolsas depende do par\n// (id_hospital, tipo_sanguineo), não apenas de um deles.\n// =============================================================\n\nmodel Stock {\n  id_stock           Int           @id @default(autoincrement())\n  id_hospital        Int\n  tipo_sanguineo     TipoSanguineo\n  /// Saldo atual; atualizado a cada MovimentoStock\n  quantidade_bolsas  Int           @default(0)\n  ultima_atualizacao DateTime      @default(now()) @updatedAt\n\n  hospital   Hospital         @relation(fields: [id_hospital], references: [id_hospital], onDelete: Cascade)\n  movimentos MovimentoStock[]\n\n  @@unique([id_hospital, tipo_sanguineo])\n  @@index([id_hospital])\n  @@map(\"stock\")\n}\n\n// Cada linha = um evento de incremento ou decremento.\n// Todos os campos dependem apenas de id_movimento (2FN/3FN ok).\nmodel MovimentoStock {\n  id_movimento   Int      @id @default(autoincrement())\n  id_stock       Int\n  /// Positivo = entrada de bolsas; negativo = consumo/saída\n  quantidade     Int\n  observacao     String?  @db.VarChar(255)\n  data_movimento DateTime @default(now())\n\n  stock Stock @relation(fields: [id_stock], references: [id_stock], onDelete: Cascade)\n\n  @@index([id_stock])\n  @@index([data_movimento])\n  @@map(\"movimento_stock\")\n}\n\n// =============================================================\n// 6. PEDIDO DE SANGUE (hospital → doadores via SMS)\n// localizacao normalizada: substituída por FK id_municipio_pedido.\n// =============================================================\n\nmodel Pedido {\n  id_pedido                 Int           @id @default(autoincrement())\n  id_hospital               Int\n  tipo_sanguineo_necessario TipoSanguineo\n  quantidade_necessaria     Int           @default(1)\n  id_municipio_pedido       Int\n  contacto_referencia       String        @db.VarChar(15)\n  nivel_urgencia            NivelUrgencia\n  mensagem_adicional        String?       @db.VarChar(160)\n  data_pedido               DateTime      @default(now())\n  data_fechamento           DateTime?\n  status_pedido             StatusPedido  @default(ativo)\n  /// Cache: COUNT(Notificacao) WHERE id_pedido = X\n  total_notificados         Int           @default(0)\n\n  hospital        Hospital      @relation(fields: [id_hospital], references: [id_hospital])\n  municipioPedido Municipio     @relation(fields: [id_municipio_pedido], references: [id_municipio])\n  notificacoes    Notificacao[]\n\n  @@index([tipo_sanguineo_necessario])\n  @@index([status_pedido])\n  @@index([data_pedido])\n  @@map(\"pedido\")\n}\n\n// =============================================================\n// 7. PEDIDO DE DOAÇÃO (doador → hospital pede para ir doar)\n// 2FN/3FN: cada campo depende exclusivamente de id_pedido_doacao.\n// =============================================================\n\nmodel PedidoDoacao {\n  id_pedido_doacao Int                @id @default(autoincrement())\n  id_doador        Int\n  id_hospital      Int\n  mensagem         String?            @db.VarChar(255)\n  status           StatusPedidoDoacao @default(pendente)\n  /// Preenchido pelo hospital ao rejeitar\n  motivo_rejeicao  String?            @db.VarChar(255)\n  data_solicitacao DateTime           @default(now())\n  data_resposta    DateTime?\n\n  doador   Doador   @relation(fields: [id_doador], references: [id_doador])\n  hospital Hospital @relation(fields: [id_hospital], references: [id_hospital])\n\n  @@index([id_doador])\n  @@index([id_hospital])\n  @@index([status])\n  @@map(\"pedido_doacao\")\n}\n\n// =============================================================\n// 8. AGENDA\n// Regra de negócio (município do doador = município do hospital)\n// verificada na camada de aplicação via JOIN com Municipio.\n// 3FN: nenhum campo depende de outro não-chave.\n// =============================================================\n\nmodel Agenda {\n  id_agenda           Int          @id @default(autoincrement())\n  id_doador           Int\n  id_hospital         Int\n  data_agendada       DateTime     @db.Date\n  hora_agendada       DateTime     @db.Time\n  status              StatusAgenda @default(pendente)\n  observacao_doador   String?      @db.VarChar(255)\n  /// Confirmação ou justificativa de rejeição pelo hospital\n  observacao_hospital String?      @db.VarChar(255)\n  data_criacao        DateTime     @default(now())\n  data_atualizacao    DateTime     @updatedAt\n\n  doador   Doador   @relation(fields: [id_doador], references: [id_doador])\n  hospital Hospital @relation(fields: [id_hospital], references: [id_hospital])\n\n  @@index([id_doador])\n  @@index([id_hospital])\n  @@index([data_agendada])\n  @@index([status])\n  @@map(\"agenda\")\n}\n\n// =============================================================\n// 9. NOTIFICAÇÃO SMS\n// 2FN CORRIGIDA: telefone_destino removido — dependia de Doador,\n// não de id_notificacao. Obtido via doador.telefone no JOIN.\n// =============================================================\n\nmodel Notificacao {\n  id_notificacao   Int               @id @default(autoincrement())\n  id_pedido        Int\n  id_doador        Int\n  mensagem_enviada String            @db.Text\n  data_envio       DateTime          @default(now())\n  status_envio     StatusNotificacao\n  /// Código retornado pelo gateway SMS em caso de falha\n  codigo_erro      String?           @db.VarChar(50)\n\n  pedido Pedido @relation(fields: [id_pedido], references: [id_pedido])\n  doador Doador @relation(fields: [id_doador], references: [id_doador])\n\n  @@index([id_pedido])\n  @@index([id_doador])\n  @@index([data_envio])\n  @@map(\"notificacao\")\n}\n\n// =============================================================\n// 10. MENSAGEM ENTRE HOSPITAIS\n// 3FN CORRIGIDA: tipo_sanguineo e quantidade_bolsas removidos —\n// dependiam do pedido, não da mensagem. Ficam em PedidoEntreHospitais.\n// Uma mensagem pode referenciar opcionalmente um pedido (FK opcional).\n// =============================================================\n\nmodel Mensagem {\n  id_mensagem     Int            @id @default(autoincrement())\n  id_remetente    Int\n  id_destinatario Int\n  /// Referência opcional a um pedido formal de sangue entre hospitais\n  id_pedido_entre Int?\n  assunto         String?        @db.VarChar(150)\n  conteudo        String         @db.Text\n  status          StatusMensagem @default(enviada)\n  data_envio      DateTime       @default(now())\n  data_leitura    DateTime?\n\n  remetente    Hospital              @relation(\"Remetente\", fields: [id_remetente], references: [id_hospital])\n  destinatario Hospital              @relation(\"Destinatario\", fields: [id_destinatario], references: [id_hospital])\n  pedidoEntre  PedidoEntreHospitais? @relation(fields: [id_pedido_entre], references: [id_pedido_entre])\n\n  @@index([id_remetente])\n  @@index([id_destinatario])\n  @@index([id_pedido_entre])\n  @@index([data_envio])\n  @@map(\"mensagem\")\n}\n\n// Pedido formal de bolsas de sangue de um hospital para outro.\n// Separado de Mensagem para satisfazer a 3FN.\nmodel PedidoEntreHospitais {\n  id_pedido_entre   Int                        @id @default(autoincrement())\n  id_solicitante    Int\n  id_fornecedor     Int\n  tipo_sanguineo    TipoSanguineo\n  quantidade_bolsas Int\n  status            StatusPedidoEntreHospitais @default(pendente)\n  motivo_rejeicao   String?                    @db.VarChar(255)\n  data_solicitacao  DateTime                   @default(now())\n  data_resposta     DateTime?\n\n  solicitante Hospital   @relation(\"HospitalSolicitante\", fields: [id_solicitante], references: [id_hospital])\n  fornecedor  Hospital   @relation(\"HospitalFornecedor\", fields: [id_fornecedor], references: [id_hospital])\n  mensagens   Mensagem[]\n\n  @@index([id_solicitante])\n  @@index([id_fornecedor])\n  @@index([status])\n  @@map(\"pedido_entre_hospitais\")\n}\n\n// =============================================================\n// 11. SESSÃO ADMIN (hospital logado)\n// =============================================================\n\nmodel SessaoAdmin {\n  id_sessao      String   @id @db.VarChar(64)\n  id_hospital    Int\n  ip_origem      String   @db.VarChar(45)\n  user_agent     String?  @db.VarChar(255)\n  data_login     DateTime @default(now())\n  data_expiracao DateTime\n  ativo          Boolean  @default(true)\n\n  hospital Hospital @relation(fields: [id_hospital], references: [id_hospital])\n\n  @@index([id_hospital])\n  @@index([ativo])\n  @@index([data_expiracao])\n  @@map(\"sessao_admin\")\n}\n\n// =============================================================\n// 12. SESSÃO DOADOR\n// =============================================================\n\nmodel SessaoDoador {\n  id_sessao      String   @id @db.VarChar(64)\n  id_doador      Int\n  ip_origem      String   @db.VarChar(45)\n  user_agent     String?  @db.VarChar(255)\n  data_login     DateTime @default(now())\n  data_expiracao DateTime\n  ativo          Boolean  @default(true)\n\n  doador Doador @relation(fields: [id_doador], references: [id_doador])\n\n  @@index([id_doador])\n  @@index([ativo])\n  @@map(\"sessao_doador\")\n}\n\n// =============================================================\n// 13. LOG DE ACESSO / AUDITORIA\n// id_hospital e id_doador opcionais (ações anónimas permitidas).\n// =============================================================\n\nmodel LogAcesso {\n  id_log      Int      @id @default(autoincrement())\n  id_hospital Int?\n  id_doador   Int?\n  acao        String   @db.VarChar(50)\n  descricao   String   @db.Text\n  ip_origem   String   @db.VarChar(45)\n  data_hora   DateTime @default(now())\n\n  hospital Hospital? @relation(fields: [id_hospital], references: [id_hospital])\n  doador   Doador?   @relation(fields: [id_doador], references: [id_doador])\n\n  @@index([id_hospital])\n  @@index([id_doador])\n  @@index([data_hora])\n  @@index([acao])\n  @@map(\"log_acesso\")\n}\n"
}

